style:
.demo[data-v-topk-pipeline] {
  max-width: 660px;
  margin: 0 auto;
  font-family: -apple-system, 'PingFang SC', sans-serif;
  color: #1f2329;
}
.bar[data-v-topk-pipeline] {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 6px;
  flex-wrap: wrap;
  gap: 6px;
}
.btns button[data-v-topk-pipeline] {
  font: inherit;
  cursor: pointer;
  background: #fff;
  color: #1f2329;
  border: 1px solid #d9dee5;
  border-radius: 6px;
  padding: 5px 12px;
  font-size: 0.85rem;
  margin-right: 6px;
}
.btns button[data-v-topk-pipeline]:hover:not(:disabled) { border-color: #1677ff; color: #1677ff;
}
.btns button[data-v-topk-pipeline]:disabled { opacity: 0.45; cursor: not-allowed;
}
.status[data-v-topk-pipeline] { font-size: 0.82rem; color: #8a909c;
}
.status.ok[data-v-topk-pipeline] { color: #2f8f6b;
}
.params[data-v-topk-pipeline] {
  font-size: 0.76rem;
  color: #8a909c;
  background: #f2f5fa;
  border: 1px solid #e7ecf3;
  border-radius: 6px;
  padding: 4px 10px;
  margin-bottom: 8px;
}
.params b[data-v-topk-pipeline] { color: #1677ff; font-weight: 600;
}
.stage[data-v-topk-pipeline] {
  width: 100%;
  background: #f7f9fc;
  border: 1px solid #e7ecf3;
  border-radius: 10px;
}
.rowlbl text[data-v-topk-pipeline] { font-size: 11px; fill: #b3bac6; transition: fill 0.3s;
}
.rowlbl text.active[data-v-topk-pipeline] { fill: #1677ff;
}
.rowlbl text.done[data-v-topk-pipeline] { fill: #2f8f6b;
}

/* 输入 chunk */
.slice[data-v-topk-pipeline] { fill: #eef2f8; stroke: #d4dcea; stroke-width: 1; transition: all 0.25s;
}
.slice.input[data-v-topk-pipeline] { fill: #e8f1ff; stroke: #9cc1f5;
}
.slice.active[data-v-topk-pipeline] { fill: #1677ff; stroke: #1677ff;
}
.slice.done[data-v-topk-pipeline] { fill: #eaf4ef; stroke: #b6dcc8;
}

/* 节点 */
.node[data-v-topk-pipeline] { fill: #eef1f6; stroke: #d3dae4; stroke-width: 1.4; transition: all 0.3s;
}
.node.active[data-v-topk-pipeline] { fill: #e8f1ff; stroke: #1677ff;
}
.node.done[data-v-topk-pipeline] { fill: #eaf4ef; stroke: #86c4a6;
}
.node.final.active[data-v-topk-pipeline] { fill: #e6f7ef; stroke: #2f8f6b; stroke-width: 2;
}
.ntxt[data-v-topk-pipeline] { text-anchor: middle; font-size: 12px; font-weight: 600; fill: #aab2bf; transition: fill 0.3s;
}
.ntxt.active[data-v-topk-pipeline] { fill: #1677ff;
}
.ntxt.done[data-v-topk-pipeline] { fill: #2f8f6b;
}
.ntxt.big[data-v-topk-pipeline] { font-size: 13px;
}
.sub[data-v-topk-pipeline] { text-anchor: middle; font-size: 10px; fill: #c2c9d4; transition: fill 0.3s;
}
.sub.active[data-v-topk-pipeline] { fill: #4f9d7d;
}

/* 箭头 */
.arrow[data-v-topk-pipeline] { stroke: #dfe4ec; stroke-width: 1.6; fill: none; transition: stroke 0.3s;
}
.arrow.active[data-v-topk-pipeline] { stroke: #1677ff; stroke-dasharray: 5 4; animation: pl-flow-topk-pipeline 0.7s linear infinite;
}
.arrow.done[data-v-topk-pipeline] { stroke: #aedcc6;
}

/* 自循环弧 */
.loop[data-v-topk-pipeline] { fill: none; stroke: #d6dde7; stroke-width: 1.6; transition: stroke 0.3s;
}
.loop.active[data-v-topk-pipeline] { stroke: #1677ff; stroke-dasharray: 4 3; animation: pl-flow-topk-pipeline 0.6s linear infinite;
}
.loop.done[data-v-topk-pipeline] { stroke: #b6dcc8;
}
#pl-loop path[data-v-topk-pipeline] { fill: #cbd2dc;
}
.loop.active[data-v-topk-pipeline] ~ * {
} /* noop */
marker path[data-v-topk-pipeline] { fill: #cbd2dc;
}

/* 操作标签 */
.op[data-v-topk-pipeline] { text-anchor: middle; font-size: 10.5px; fill: #c2c9d4; font-weight: 600; transition: fill 0.3s;
}
.op.active[data-v-topk-pipeline] { fill: #1677ff;
}
.op.done[data-v-topk-pipeline] { fill: #5fa888;
}
.cnt[data-v-topk-pipeline] { text-anchor: middle; font-size: 10px; fill: #aab2bf;
}
@keyframes pl-flow-topk-pipeline {
to { stroke-dashoffset: -9;
}
}
.cap[data-v-topk-pipeline] {
  font-size: 0.85rem;
  line-height: 1.7;
  color: #5c6370;
  margin-top: 10px;
}
.cap b[data-v-topk-pipeline] { color: #1677ff;
}

